import{_ as t,c as o,o as n,ag as s}from"./chunks/framework.Bw-5EFTY.js";const u=JSON.parse('{"title":"Architecture","description":"","frontmatter":{},"headers":[],"relativePath":"guide/architecture.md","filePath":"guide/architecture.md"}'),a={name:"guide/architecture.md"};function r(d,e,i,c,l,p){return n(),o("div",null,e[0]||(e[0]=[s(`<h1 id="architecture" tabindex="-1">Architecture <a class="header-anchor" href="#architecture" aria-label="Permalink to &quot;Architecture&quot;">​</a></h1><h2 id="layer-structure" tabindex="-1">Layer Structure <a class="header-anchor" href="#layer-structure" aria-label="Permalink to &quot;Layer Structure&quot;">​</a></h2><p>Robota SDK follows a strict bottom-up layered assembly model. Each layer builds on the layer below.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>agent-cli         ← TUI layer: Ink TUI, useInteractiveSession hook, permission prompts</span></span>
<span class="line"><span>  ↓</span></span>
<span class="line"><span>agent-sdk         ← Assembly layer: InteractiveSession, SystemCommandExecutor,</span></span>
<span class="line"><span>  │                  CommandRegistry, BuiltinCommandSource, SkillCommandSource,</span></span>
<span class="line"><span>  │                  config, context, session factory, query()</span></span>
<span class="line"><span>  ↓</span></span>
<span class="line"><span>agent-sessions    ← Session lifecycle: permissions, hooks, compaction, persistence</span></span>
<span class="line"><span>agent-tools       ← Tool infrastructure + 8 built-in CLI tools</span></span>
<span class="line"><span>agent-providers   ← AI provider implementations (Anthropic, OpenAI, Google)</span></span>
<span class="line"><span>  ↓</span></span>
<span class="line"><span>agent-core        ← Foundation: Robota engine, abstractions, DI, events, plugins</span></span></code></pre></div><h2 id="package-roles" tabindex="-1">Package Roles <a class="header-anchor" href="#package-roles" aria-label="Permalink to &quot;Package Roles&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Package</th><th>Role</th><th>Layer</th></tr></thead><tbody><tr><td><strong>agent-core</strong></td><td>Robota engine, execution loop, provider abstraction, permissions, hooks, plugin system, model definitions (SSOT)</td><td>Foundation</td></tr><tr><td><strong>agent-tools</strong></td><td>ToolRegistry, FunctionTool, createZodFunctionTool, 8 built-in CLI tools</td><td>General</td></tr><tr><td><strong>agent-sessions</strong></td><td>Session class with permission enforcement, context tracking, compaction</td><td>General</td></tr><tr><td><strong>agent-providers</strong></td><td>AnthropicProvider, OpenAIProvider, GoogleProvider</td><td>General</td></tr><tr><td><strong>agent-sdk</strong></td><td>Assembly: InteractiveSession, SystemCommandExecutor, CommandRegistry, BuiltinCommandSource, SkillCommandSource, config loading, context discovery, createSession, query()</td><td>SDK-specific</td></tr><tr><td><strong>agent-cli</strong></td><td>Ink TUI: useInteractiveSession hook bridges SDK events → React state, permission prompts</td><td>CLI-specific</td></tr></tbody></table><h2 id="dependency-flow" tabindex="-1">Dependency Flow <a class="header-anchor" href="#dependency-flow" aria-label="Permalink to &quot;Dependency Flow&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>agent-cli ─→ agent-sdk ─→ agent-sessions ─→ agent-core</span></span>
<span class="line"><span>               ├─→ agent-tools ────────────→ agent-core</span></span>
<span class="line"><span>               ├─→ agent-provider-anthropic → agent-core</span></span>
<span class="line"><span>               └─────────────────────────→ agent-core  (types, permissions, hooks)</span></span></code></pre></div><p>Rules:</p><ul><li>Dependencies are one-way. No cycles.</li><li><code>agent-core</code> has zero workspace dependencies (foundation).</li><li><code>agent-sessions</code> depends only on <code>agent-core</code> (generic — no tools or providers).</li><li>Assembly (wiring tools + provider + prompt) happens in <code>agent-sdk</code>.</li><li><code>InteractiveSession</code> (SDK) wraps <code>Session</code> (sessions) via composition, not inheritance.</li><li><code>agent-cli</code> depends only on <code>agent-sdk</code>; it does not access <code>agent-sessions</code> or <code>agent-core</code> directly.</li></ul><h2 id="design-patterns" tabindex="-1">Design Patterns <a class="header-anchor" href="#design-patterns" aria-label="Permalink to &quot;Design Patterns&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Pattern</th><th>Where</th><th>Purpose</th></tr></thead><tbody><tr><td><strong>Facade</strong></td><td><code>Robota</code>, <code>Session</code>, <code>InteractiveSession</code></td><td>Single entry point hiding internal complexity</td></tr><tr><td><strong>Decorator</strong></td><td><code>PermissionEnforcer.wrapTools()</code></td><td>Wraps tools with permission checks</td></tr><tr><td><strong>Strategy</strong></td><td><code>IAIProvider</code>, <code>ISessionLogger</code></td><td>Swappable implementations</td></tr><tr><td><strong>Factory</strong></td><td><code>createSession()</code>, <code>createZodFunctionTool()</code></td><td>Object creation</td></tr><tr><td><strong>Null Object</strong></td><td><code>SilentLogger</code>, <code>DefaultEventService</code></td><td>Safe no-op defaults</td></tr><tr><td><strong>Registry</strong></td><td><code>ToolRegistry</code>, <code>CommandRegistry</code></td><td>Central management of tools and commands</td></tr><tr><td><strong>Composition</strong></td><td><code>InteractiveSession</code> → <code>Session</code>; <code>Session</code> → sub-components</td><td>Delegation over inheritance</td></tr></tbody></table><h2 id="session-sub-components" tabindex="-1">Session Sub-Components <a class="header-anchor" href="#session-sub-components" aria-label="Permalink to &quot;Session Sub-Components&quot;">​</a></h2><p><code>Session</code> delegates to focused sub-components:</p><table tabindex="0"><thead><tr><th>Component</th><th>Responsibility</th></tr></thead><tbody><tr><td><code>PermissionEnforcer</code></td><td>Tool wrapping, permission checks, hook execution, output truncation</td></tr><tr><td><code>ContextWindowTracker</code></td><td>Token usage tracking, auto-compact threshold</td></tr><tr><td><code>CompactionOrchestrator</code></td><td>Conversation summarization via LLM (PreCompact hook)</td></tr></tbody></table><h2 id="interactivesession" tabindex="-1">InteractiveSession <a class="header-anchor" href="#interactivesession" aria-label="Permalink to &quot;InteractiveSession&quot;">​</a></h2><p><code>InteractiveSession</code> (in <code>agent-sdk</code>) wraps <code>Session</code> via composition to provide an event-driven API suitable for any interactive client: CLI, web, API server, or dynamic worker.</p><p>Key responsibilities:</p><table tabindex="0"><thead><tr><th>Concern</th><th>Detail</th></tr></thead><tbody><tr><td><strong>submit / abort</strong></td><td><code>submit(input)</code> starts a run; <code>abort()</code> cancels the current run</td></tr><tr><td><strong>cancelQueue</strong></td><td>Cancels the pending queued prompt without aborting the in-flight run</td></tr><tr><td><strong>Prompt queue</strong></td><td>Queues a new prompt submitted while a run is in progress</td></tr><tr><td><strong>Event emission</strong></td><td>Emits typed events (<code>textDelta</code>, <code>message</code>, <code>statusChange</code>, etc.) consumed by clients</td></tr><tr><td><strong>SystemCommandExecutor</strong></td><td>Handles built-in system commands (help, clear, compact, mode, model, etc.) before forwarding to the LLM</td></tr><tr><td><strong>CommandRegistry</strong></td><td>Aggregates <code>BuiltinCommandSource</code> and <code>SkillCommandSource</code> for slash-command discovery</td></tr></tbody></table><p>The CLI&#39;s <code>useInteractiveSession</code> hook subscribes to these events and translates them into React state. <code>InteractiveSession</code> itself has no React dependency.</p><h2 id="plugin-architecture" tabindex="-1">Plugin Architecture <a class="header-anchor" href="#plugin-architecture" aria-label="Permalink to &quot;Plugin Architecture&quot;">​</a></h2><p><code>agent-core</code> defines the <code>AbstractPlugin</code> base class. 9 plugin implementations are available as separate <code>@robota-sdk/agent-plugin-*</code> packages. <code>EventEmitterPlugin</code> is also built directly into <code>agent-core</code> so that consumers do not need an additional dependency for basic event emission.</p><p>Plugins integrate with the agent lifecycle via hooks: <code>beforeRun</code>, <code>afterRun</code>, <code>onError</code>, <code>onStreamChunk</code>, <code>beforeToolExecution</code>, <code>afterToolExecution</code>.</p><h2 id="changes-from-v2-0-0" tabindex="-1">Changes from v2.0.0 <a class="header-anchor" href="#changes-from-v2-0-0" aria-label="Permalink to &quot;Changes from v2.0.0&quot;">​</a></h2><p>In v2.0.0, <code>agent-core</code> contained everything: tools, plugins, session management. In v3.0.0:</p><ul><li><strong>Tools</strong> moved to <code>agent-tools</code> (FunctionTool, ToolRegistry, built-in tools)</li><li><strong>Plugins</strong> extracted to <code>agent-plugin-*</code> packages</li><li><strong>Session</strong> created as a new package (<code>agent-sessions</code>) with permission and hook support</li><li><strong>SDK</strong> created as a new assembly layer (<code>agent-sdk</code>) with config/context loading</li><li><strong>CLI</strong> created as a new terminal UI (<code>agent-cli</code>)</li><li><strong>Permissions</strong> and <strong>Hooks</strong> added to <code>agent-core</code> as general-purpose infrastructure</li></ul>`,26)]))}const h=t(a,[["render",r]]);export{u as __pageData,h as default};
